from itertools import combinations_with_replacement as cwr
def is_B3(S, n):
    sums = set()
    for a, b, c in cwr(S, 3):
        t = tuple(a[i] + b[i] + c[i] for i in range(n))
        if t in sums:
            return False
        sums.add(t)
    return True
# a(n) is the maximum size of a B_3 subset of {0,1}^n; is_B3 verifies a candidate set.

